+fn unique_constraint_collation_is_indexable(collation: Option<&str>) -> bool {
+    match collation {
+        None => true,
+        Some(name)
+            if name.eq_ignore_ascii_case("BINARY")
+                || name.eq_ignore_ascii_case("NOCASE")
+                || name.eq_ignore_ascii_case("RTRIM") =>
+        {
