+        }
+        Some(_) => false,
+    }
+}
+
+fn unique_constraint_supports_index(collations: &[Option<String>]) -> bool {
+    collations
+        .iter()
+        .all(|collation| unique_constraint_collation_is_indexable(collation.as_deref()))
+}
